   325→func (s *PgStore) CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error) {
   326→	tx, err := s.pool.Begin(ctx)
   327→	if err != nil {
   328→		return nil, fmt.Errorf("begin tx: %w", err)
   329→	}
   330→	defer tx.Rollback(ctx)
   331→
   332→	var result []models.Subscription
   333→	for i := range subs {
   334→		sub := subs[i]
   335→		err := tx.QueryRow(ctx,
   336→			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   337→			 VALUES ($1, $2, $3, $4, $5)
   338→			 RETURNING id, created_at`,
   339→			sub.ChannelID, sub.Type, sub.SourceID, sub.ProjectID, sub.VersionFilter,
   340→		).Scan(&sub.ID, &sub.CreatedAt)
   341→		if err != nil {
   342→			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
   343→		}
   344→		result = append(result, sub)
   345→	}
   346→
   347→	if err := tx.Commit(ctx); err != nil {
   348→		return nil, fmt.Errorf("commit tx: %w", err)
   349→	}
   350→	return result, nil
   351→}
