   918→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   919→	// Validate granularity to one of three literal values (no injection risk).
   920→	var trunc string
   921→	switch granularity {
   922→	case "daily":
   923→		trunc = "day"
   924→	case "weekly":
   925→		trunc = "week"
   926→	case "monthly":
   927→		trunc = "month"
   928→	default:
   929→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   930→	}
   931→
   932→	query := fmt.Sprintf(`
   933→		WITH buckets AS (
   934→			SELECT date_trunc('%s', gs)::date AS period
   935→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   936→		)
   937→		SELECT
   938→			b.period,
   939→			COALESCE(r.cnt, 0) AS releases,
   940→			COALESCE(sr.cnt, 0) AS semantic_releases
   941→		FROM buckets b
   942→		LEFT JOIN (
   943→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
   944→			       COUNT(*) AS cnt
   945→			FROM releases
   946→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
   947→			GROUP BY 1
   948→		) r ON r.period = b.period
   949→		LEFT JOIN (
   950→			SELECT date_trunc('%s', created_at)::date AS period,
   951→			       COUNT(*) AS cnt
   952→			FROM semantic_releases
   953→			WHERE created_at >= $1 AND created_at < $2
   954→			GROUP BY 1
   955→		) sr ON sr.period = b.period
   956→		ORDER BY b.period
   957→	`, trunc, trunc, trunc, trunc)
   958→
   959→	rows, err := s.pool.Query(ctx, query, start, end)
   960→	if err != nil {
   961→		return nil, fmt.Errorf("get trend: %w", err)
   962→	}
   963→	defer rows.Close()
   964→
   965→	var buckets []TrendBucket
   966→	for rows.Next() {
   967→		var b TrendBucket
   968→		var period time.Time
   969→		if err := rows.Scan(&period, &b.Releases, &b.SemanticReleases); err != nil {
   970→			return nil, fmt.Errorf("scan trend bucket: %w", err)
   971→		}
   972→		b.Period = period.Format("2006-01-02")
   973→		buckets = append(buckets, b)
   974→	}
   975→	if buckets == nil {
   976→		buckets = []TrendBucket{}
   977→	}
   978→	return buckets, nil
   979→}
