   180→// BatchSubscriptionInput is the request body for POST /subscriptions/batch.
   181→type BatchSubscriptionInput struct {
   182→	ChannelID     string   `json:"channel_id"`
   183→	Type          string   `json:"type"`
   184→	ProjectIDs    []string `json:"project_ids"`
