   189→// BatchCreate handles POST /subscriptions/batch — creates multiple subscriptions at once.
   190→func (h *SubscriptionsHandler) BatchCreate(w http.ResponseWriter, r *http.Request) {
   191→	var input BatchSubscriptionInput
   192→	if err := DecodeJSON(r, &input); err != nil {
   193→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   194→		return
   195→	}
   196→	input.Type = strings.TrimSpace(input.Type)
   197→	input.ChannelID = strings.TrimSpace(input.ChannelID)
   198→	if input.Type != "source" && input.Type != "project" {
   199→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source' or 'project'")
   200→		return
   201→	}
   202→	if input.ChannelID == "" {
   203→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
   204→		return
   205→	}
   206→
   207→	var subs []models.Subscription
   208→	if input.Type == "project" {
   209→		if len(input.ProjectIDs) == 0 {
   210→			RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_ids must not be empty when type is 'project'")
   211→			return
   212→		}
   213→		for _, pid := range input.ProjectIDs {
   214→			id := pid
   215→			subs = append(subs, models.Subscription{
   216→				ChannelID:     input.ChannelID,
   217→				Type:          input.Type,
   218→				ProjectID:     &id,
   219→				VersionFilter: input.VersionFilter,
   220→			})
   221→		}
   222→	} else {
   223→		if len(input.SourceIDs) == 0 {
   224→			RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_ids must not be empty when type is 'source'")
   225→			return
   226→		}
   227→		for _, sid := range input.SourceIDs {
   228→			id := sid
   229→			subs = append(subs, models.Subscription{
   230→				ChannelID:     input.ChannelID,
   231→				Type:          input.Type,
   232→				SourceID:      &id,
   233→				VersionFilter: input.VersionFilter,
   234→			})
   235→		}
   236→	}
   237→
   238→	created, err := h.store.CreateSubscriptionBatch(r.Context(), subs)
   239→	if err != nil {
   240→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscriptions")
   241→		return
