   247→**Step 2: Add `CreateSubscriptionBatch` to `internal/api/pgstore.go`**
   248→
   249→Add after the existing `CreateSubscription` method (around line 323):
   250→
   251→```go
   252→func (s *PgStore) CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error) {
   253→	tx, err := s.pool.Begin(ctx)
   254→	if err != nil {
   255→		return nil, fmt.Errorf("begin tx: %w", err)
   256→	}
   257→	defer tx.Rollback(ctx)
   258→
   259→	var result []models.Subscription
   260→	for i := range subs {
   261→		sub := subs[i]
   262→		err := tx.QueryRow(ctx,
   263→			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   264→			 VALUES ($1, $2, $3, $4, $5)
   265→			 RETURNING id, created_at`,
   266→			sub.ChannelID, sub.Type, sub.SourceID, sub.ProjectID, sub.VersionFilter,
   267→		).Scan(&sub.ID, &sub.CreatedAt)
   268→		if err != nil {
   269→			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
   270→		}
   271→		result = append(result, sub)
   272→	}
   273→
   274→	if err := tx.Commit(ctx); err != nil {
   275→		return nil, fmt.Errorf("commit tx: %w", err)
   276→	}
   277→	return result, nil
   278→}
   279→```
